(()=>{function r(){return location.protocol==="file:"&&location.pathname.endsWith("/")&&!!document.querySelector("#listing, #parentDirLinkBox, table")}function o(){if(!r())return;let e=Array.from(document.querySelectorAll("a[href]")).filter(n=>/\.(md|markdown|mdown|mkd|mkdn|mdx)$/i.test(n.getAttribute("href")||""));if(!e.length)return;for(let n of e)n.classList.add("skim-md-link");let t=document.createElement("div");t.className="skim-folder-banner",t.textContent=`\u{1F4C4} ${e.length} markdown file${e.length===1?"":"s"} here \u2014 click any to read with Skim`,document.body.prepend(t)}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",o,{once:!0}):o();})();
